export type ClaudeSshPlatform = 'linux-amd64' | 'linux-arm64' | 'darwin-amd64' | 'darwin-arm64' | 'windows-amd64' | 'windows-arm64';
export type ClaudeSshPlatformManifest = { checksum: string; size: number };
export const version: string;
export const requiredVersion: string;
export const baseUrl: string;
export const manifest: { version: string; platforms: Record<ClaudeSshPlatform, ClaudeSshPlatformManifest> };
export function getReleaseMetadata(): { version: string; manifest: typeof manifest; baseUrl: string };
export function getPlatformKey(platform?: NodeJS.Platform, arch?: NodeJS.Architecture): ClaudeSshPlatform | string;
export function getPlatformManifest(platformKey?: string): ClaudeSshPlatformManifest | null;
export function getDownloadUrl(platformKey?: string): string;
export function listPlatforms(): ClaudeSshPlatform[];
export function getDefaultStorageDir(): string;
export function getVersionDir(storageDir?: string): string;
export function getBinaryPath(platformKey?: string, storageDir?: string): string;
export function getVerifiedMarkerPath(platformKey?: string, storageDir?: string): string;
export function verifyBinary(filePath: string, platformKey?: string): Promise<{ ok: boolean; error?: string; size?: number; checksum?: string; expected?: ClaudeSshPlatformManifest }>;
export function binaryExists(platformKey?: string, storageDir?: string): Promise<boolean>;
export function downloadBinary(platformKey?: string, options?: { storageDir?: string }): Promise<{ ready: true; path: string; bytesDownloaded: number | null }>;
export function prepare(platformKey?: string, options?: { storageDir?: string }): Promise<{ ready: true; path: string } | { ready: false; error: string }>;
